  1→/**
  2→ * Protocol types for communication between the Rust core and TypeScript frontend.
  3→ *
  4→ * All messages are newline-delimited JSON over stdin/stdout. The core sends
  5→ * Request messages and receives Response messages back. Every message includes
  6→ * a protocol version for compatibility checking.
  7→ */
  8→
  9→export const PROTOCOL_VERSION = "0.1.0";
 10→export const FRONTEND_LANGUAGE = "typescript";
 11→
 12→// ---------------------------------------------------------------------------
 13→// Request: Core → Frontend
 14→// ---------------------------------------------------------------------------
 15→
 16→export type SetupMode = "per_function" | "per_execution";
 17→
 18→export type SetupLevel = "session" | "file" | "function" | "execution";
 19→
 20→export interface SetupContextEntry {
 21→  level: SetupLevel;
 22→  context: unknown;
 23→}
 24→
 25→export interface SetupContextStack {
 26→  contexts: SetupContextEntry[];
 27→}
 28→
 29→export type GeneratorKind = "type_name" | "param_name";
 30→
 31→export type Command =
 32→  | "handshake"
 33→  | "analyze"
 34→  | "instrument"
 35→  | "execute"
 36→  | "setup"
 37→  | "teardown"
 38→  | "generate"
 39→  | "shutdown";
 40→
 41→export interface MockConfig {
 42→  symbol: string;
 43→  return_values: unknown[];
 44→  should_track_calls: boolean;
 45→  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
 46→}
 47→
 48→interface BaseRequest {
 49→  protocol_version: string;
 50→  id: number;
 51→  command: Command;
 52→}
 53→
 54→export interface HandshakeRequest extends BaseRequest {
 55→  command: "handshake";
 56→  capabilities: string[];
 57→}
 58→
 59→export interface AnalyzeRequest extends BaseRequest {
 60→  command: "analyze";
 61→  file: string;
 62→  function?: string | null;
 63→  project_root?: string | null;
 64→}
 65→
 66→export interface InstrumentRequest extends BaseRequest {
 67→  command: "instrument";
 68→  file: string;
 69→  function: string;
 70→  mocks: MockConfig[];
 71→  project_root?: string | null;
 72→}
 73→
 74→export interface ExecuteRequest extends BaseRequest {
 75→  command: "execute";
 76→  function: string;
 77→  inputs: unknown[];
 78→  mocks: MockConfig[];
 79→  setup_context?: SetupContextStack | null;
 80→}
 81→
 82→export interface SetupRequest extends BaseRequest {
 83→  command: "setup";
 84→  file: string;
 85→  scope: string;
 86→  level: SetupLevel;
 87→  parent_context?: SetupContextStack | null;
 88→  project_root?: string | null;
 89→}
 90→
 91→export interface TeardownRequest extends BaseRequest {
 92→  command: "teardown";
 93→  scope: string;
 94→  level: SetupLevel;
 95→}
 96→
 97→export interface GenerateRequest extends BaseRequest {
 98→  command: "generate";
 99→  file: string;
100→  name: string;
101→  kind: GeneratorKind;
102→  recipe?: unknown;
103→  project_root?: string | null;
104→}
105→
106→export interface ShutdownRequest extends BaseRequest {
107→  command: "shutdown";
108→}
109→
110→export type Request =
111→  | HandshakeRequest
112→  | AnalyzeRequest
113→  | InstrumentRequest
114→  | ExecuteRequest
115→  | SetupRequest
116→  | TeardownRequest
117→  | GenerateRequest
118→  | ShutdownRequest;
119→
120→// ---------------------------------------------------------------------------
121→// Response: Frontend → Core
122→// ---------------------------------------------------------------------------
123→
124→export type ResponseStatus =
125→  | "handshake"
126→  | "analyze"
127→  | "instrument"
128→  | "execute"
129→  | "setup"
130→  | "teardown_ack"
131→  | "generate"
132→  | "shutdown_ack"
133→  | "error";
134→
135→export type ErrorCode =
136→  | "file_not_found"
137→  | "function_not_found"
138→  | "parse_error"
139→  | "instrumentation_failed"
140→  | "execution_timeout"
141→  | "execution_crash"
142→  | "version_mismatch"
143→  | "invalid_request"
144→  | "compilation_error"
145→  | "internal_error";
146→
147→interface BaseResponse {
148→  protocol_version: string;
149→  id: number;
150→  status: ResponseStatus;
151→}
152→
153→export interface HandshakeResponse extends BaseResponse {
154→  status: "handshake";
155→  frontend_version: string;
156→  language: string;
157→  capabilities: string[];
158→}
159→
160→export interface AnalyzeResponse extends BaseResponse {
161→  status: "analyze";
162→  functions: FunctionAnalysis[];
163→}
164→
165→export interface InstrumentResponse extends BaseResponse {
166→  status: "instrument";
167→  instrumented: boolean;
168→  output_file: string | null;
169→  instrumentable_line_count?: number;
170→}
171→
172→export interface ExecuteResponse extends BaseResponse {
173→  status: "execute";
174→  return_value: unknown;
175→  thrown_error: ErrorInfo | null;
176→  branch_path: BranchDecision[];
177→  lines_executed: number[];
178→  calls_to_external: ExternalCall[];
179→  path_constraints: SymConstraint[];
180→  side_effects: SideEffect[];
181→  performance: PerformanceMetrics;
182→  capture_truncation?: TruncationInfo;
183→  scope_events?: TraceEvent[];
184→}
185→
186→export interface SetupResponse extends BaseResponse {
187→  status: "setup";
188→  setup_context: unknown;
189→}
190→
191→export interface TeardownAckResponse extends BaseResponse {
192→  status: "teardown_ack";
193→}
194→
195→export interface GenerateResponse extends BaseResponse {
196→  status: "generate";
197→  value: unknown;
198→  generator_id: string;
199→  recipe?: unknown;
200→}
201→
202→export interface ShutdownAckResponse extends BaseResponse {
203→  status: "shutdown_ack";
204→}
205→
206→export interface ErrorResponse extends BaseResponse {
207→  status: "error";
208→  code: ErrorCode;
209→  message: string;
210→  details?: unknown;
211→}
212→
213→export type Response =
214→  | HandshakeResponse
215→  | AnalyzeResponse
216→  | InstrumentResponse
217→  | ExecuteResponse
218→  | SetupResponse
219→  | TeardownAckResponse
220→  | GenerateResponse
221→  | ShutdownAckResponse
222→  | ErrorResponse;
223→
224→// ---------------------------------------------------------------------------
225→// Supporting types
226→// ---------------------------------------------------------------------------
227→
228→/** A literal constant extracted from source code for use as a candidate test input. */
229→export type LiteralValue =
230→  | { type: "int"; value: number }
231→  | { type: "float"; value: number }
232→  | { type: "str"; value: string }
233→  | { type: "bool"; value: boolean }
234→  | { type: "regex"; pattern: string };
235→
236→export interface CryptoBoundary {
237→  symbol: string;
238→  source_module: string;
239→  direction: "encrypt" | "decrypt" | "both";
240→  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
241→  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
242→  call_sites: number[];
243→}
244→
245→export interface FunctionAnalysis {
246→  name: string;
247→  exported?: boolean;
248→  params: ParamInfo[];
249→  branches: BranchInfo[];
250→  dependencies: ExternalDependency[];
251→  return_type: TypeInfo;
252→  start_line: number;
253→  end_line: number;
254→  literals?: LiteralValue[];
255→  crypto_boundaries?: CryptoBoundary[];
256→}
257→
258→export interface ParamInfo {
259→  name: string;
260→  type: TypeInfo;
261→  type_name?: string;
262→}
263→
264→/** Well-known complex types beyond primitives and structural types. */
265→export type ComplexKind =
266→  | "date" | "date_time" | "time" | "duration"
267→  | "reg_exp" | "char" | "symbol"
268→  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
269→  | "buffer" | "bit_set"
270→  | "error" | "option" | "result"
271→  | "closure" | "iterator"
272→  | "url" | "ip_address"
273→  | "uuid"
274→  | "path"
275→  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
276→  | "rune" | "go_byte";
277→
278→export type TypeInfo =
279→  | { kind: "int" }
280→  | { kind: "float" }
281→  | { kind: "str" }
282→  | { kind: "bool" }
283→  | { kind: "unknown" }
284→  | { kind: "array"; element: TypeInfo }
285→  | { kind: "object"; fields: [string, TypeInfo][] }
286→  | { kind: "union"; variants: TypeInfo[] }
287→  | { kind: "nullable"; inner: TypeInfo }
288→  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
289→  | { kind: "opaque"; label: string };
290→
291→export interface BranchInfo {
292→  id: number;
293→  line: number;
294→  condition_text: string;
295→  condition: SymExpr | null;
296→  branch_type: BranchType;
297→}
298→
299→export type BranchType =
300→  | "if"
301→  | "else_if"
302→  | "switch"
303→  | "ternary"
304→  | "logical_and"
305→  | "logical_or"
306→  | "while"
307→  | "for";
308→
309→export type SymExpr =
310→  | { kind: "param"; name: string; path: string[] }
311→  | SymExprConst
312→  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
313→  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
314→  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
315→  | { kind: "unknown" };
316→
317→/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
318→export type SymExprConst =
319→  | { kind: "const"; type: "int"; value: number }
320→  | { kind: "const"; type: "float"; value: number }
321→  | { kind: "const"; type: "str"; value: string }
322→  | { kind: "const"; type: "bool"; value: boolean }
323→  | { kind: "const"; type: "null" }
324→  | { kind: "const"; type: "undefined" }
325→  | { kind: "const"; type: "complex"; value: { kind: ComplexKind; repr: SymExprConst } };
326→
327→export type BinOpKind =
328→  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
329→  | "add" | "sub" | "mul" | "div" | "mod"
330→  | "and" | "or"
331→  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
332→  | "in" | "instance_of";
333→
334→export type UnOpKind = "not" | "neg" | "bitwise_not" | "typeof";
335→
336→export interface BranchDecision {
337→  branch_id: number;
338→  line: number;
339→  taken: boolean;
340→  constraint: SymConstraint;
341→}
342→
343→export type ScopeEvent =
344→  | { kind: "loop_enter"; loop_id: number }
345→  | { kind: "loop_exit"; loop_id: number }
346→  | { kind: "call_enter"; call_site_id: number }
347→  | { kind: "call_exit"; call_site_id: number };
348→
349→export type TraceEvent =
350→  | { type: "branch"; decision: BranchDecision }
351→  | { type: "scope"; event: ScopeEvent };
352→
353→export type SymConstraint =
354→  | { kind: "expr"; expr: SymExpr }
355→  | { kind: "unknown"; hint: string };
356→
357→export interface ExternalCall {
358→  symbol: string;
359→  args: unknown[];
360→  return_value: unknown;
361→}
362→
363→export interface ExternalDependency {
364→  kind: DependencyKind;
365→  symbol: string;
366→  source_module: string;
367→  return_type: TypeInfo;
368→  param_types: TypeInfo[];
369→  call_sites: number[];
370→}
371→
372→export type DependencyKind =
373→  | "function_call"
374→  | "method_call"
375→  | "property_access"
376→  | "module_import";
377→
378→export type SideEffect =
379→  | { kind: "console_output"; level: string; message: string }
380→  | { kind: "file_write"; path: string; content: string }
381→  | { kind: "network_request"; method: string; url: string; body: unknown }
382→  | { kind: "environment_read"; variable: string; value: string | null }
383→  | { kind: "global_mutation"; name: string }
384→  | { kind: "thrown_error"; error_type: string; message: string; stack: string | null }
385→  | { kind: "global_state_change"; variable: string; before: unknown; after: unknown };
386→
387→export type ErrorCategory = "validation" | "runtime" | "infrastructure" | "unknown";
388→
389→export interface ErrorInfo {
390→  error_type: string;
391→  message: string;
392→  stack: string | null;
393→  error_category?: ErrorCategory;
394→}
395→
396→export interface TruncationInfo {
397→  was_truncated: boolean;
398→  original_lines: number;
399→  original_bytes: number;
400→}
401→
402→export interface PerformanceMetrics {
403→  wall_time_ms: number;
404→  cpu_time_us: number;
405→  heap_used_bytes: number;
406→  heap_allocated_bytes: number;
407→}
